// ---------- 共用：晶簇繪製小工具 ----------
function frostCrystals(p, x, y, c, cL) {
  // 沿背部生長的三根冰晶
  p.line(x, y, x - 1, y - 3, c); p.px(x - 1, y - 3, cL);
  p.line(x + 2, y, x + 2, y - 4, c); p.px(x + 2, y - 4, cL);
  p.line(x + 4, y, x + 5, y - 3, c); p.px(x + 5, y - 3, cL);
}

