// ENEMY 1 — 晶殼蟹 (t1, chase) 全新繪製
// ============================================================
Enemies.register({
  id: 'g_crystalcrab', name: '晶殼蟹', sprite: 'g_crystalcrab', ai: 'chase', tier: 1, weight: 11,
  hp: 22, speed: 34, damage: 7, radius: 6, xp: 4, gold: 2, shard: 0.02,
  bloodColor: P.iceD, tint: P.shard,
  desc: '披著結晶硬殼的洞窟蟹，成群橫行夾擊獵物。',
});
defineAnim('g_crystalcrab', 16, 12, 4, (p, f) => {
  const leg = [0, 1, 0, -1][f % 4];        // 步足擺動
  const cy = 7;
  // 八足
  for (let i = 0; i < 3; i++) {
    const ly = cy + 1 + i;
    p.line(5 - i, ly, 1, ly + leg, P.iceD);
    p.line(11 + i, ly, 15, ly - leg, P.iceD);
  }
  // 蟹螯
  p.ellipse(2, cy - 1 - leg, 2, 1.6, P.ice); p.px(1, cy - 1 - leg, P.iceD);
  p.ellipse(14, cy - 1 + leg, 2, 1.6, P.ice); p.px(15, cy - 1 + leg, P.iceD);
  // 殼身（晶體圓背）
  p.ellipse(8, cy, 5, 3.4, P.iceD);
  p.ellipse(8, cy - 0.4, 4, 2.6, P.ice);
  p.ellipse(7, cy - 1.2, 2.2, 1.4, P.shardL);
  // 殼上晶簇
  frostCrystals(p, 5, cy - 2, P.shard, P.shardL);
  // 眼柄
  p.vline(cy - 3, cy - 1, 6, P.iceD); p.vline(cy - 3, cy - 1, 10, P.iceD);
  p.px(6, cy - 4, P.ink); p.px(10, cy - 4, P.ink);
  p.px(6, cy - 4, P.red); p.px(10, cy - 4, P.red);
  p.outline(P.ink);
}, { anchor: [8, 11], fps: 7 });

